{
  "name": "Data Health Steward Agent",
  "description": "An AI-powered active data governance dashboard for SAP environments. Features automated health checks, anomaly detection, and human-in-the-loop auto-repairs."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum IssueSeverity {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export enum IssueType {
  MISSING_FIELD = 'Missing Field',
  DUPLICATE = 'Duplicate',
  FORMAT_ERROR = 'Format Error',
  OUTLIER = 'Outlier',
  REF_INTEGRITY = 'Ref Integrity'
}

export interface DataIssue {
  id: string;
  table: string;
  field: string;
  description: string;
  count: number;
  impact: string;
  severity: IssueSeverity;
  type: IssueType;
  suggestion: string;
  status: 'Open' | 'Pending' | 'Fixed';
}

export interface HealthMetric {
  name: string;
  score: number;
  trend: 'up' | 'down' | 'stable';
  color: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';

const apiKey = process.env.API_KEY || '';

// Initialize only if key exists to prevent immediate crash, handle error gracefully later
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const sendMessageToGemini = async (
  message: string,
  contextData: string
): Promise<string> => {
  if (!ai) {
    return "Error: API_KEY is missing from environment variables. Please configure your API key to use the AI Agent.";
  }

  try {
    const model = 'gemini-2.5-flash-latest'; // Fast and capable for chat

    const combinedPrompt = `
      ${SYSTEM_PROMPT}

      CURRENT DASHBOARD DATA CONTEXT:
      ${contextData}

      USER QUERY:
      ${message}
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: combinedPrompt,
    });

    return response.text || "I processed the data but couldn't generate a text response.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I encountered an error connecting to the AI brain. Please try again later.";
  }
};

