import React from 'react';
import { HealthMetric } from '../types';
import { ArrowUp, ArrowDown, Minus } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';

interface MetricCardProps {
  metric: HealthMetric;
}

export const MetricCard: React.FC<MetricCardProps> = ({ metric }) => {
  const data = [
    { name: 'Score', value: metric.score },
    { name: 'Remaining', value: 100 - metric.score },
  ];

  return (
    <div className="bg-white rounded-xl p-5 border border-gray-200 shadow-sm flex items-center justify-between hover:shadow-md transition-shadow duration-200">
      <div>
        <h3 className="text-sm font-medium text-gray-500 mb-1">{metric.name}</h3>
        <div className="flex items-end gap-3">
          <span className="text-3xl font-bold text-gray-900">{metric.score}%</span>
          <div className={`flex items-center text-sm font-medium mb-1
            ${metric.trend === 'up' ? 'text-green-600' : metric.trend === 'down' ? 'text-red-500' : 'text-gray-400'}`}>
            {metric.trend === 'up' && <ArrowUp size={16} />}
            {metric.trend === 'down' && <ArrowDown size={16} />}
            {metric.trend === 'stable' && <Minus size={16} />}
          </div>
        </div>
      </div>

      <div className="h-16 w-16 relative">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={data}
              innerRadius={20}
              outerRadius={30}
              paddingAngle={2}
              dataKey="value"
              startAngle={90}
              endAngle={-270}
              stroke="none"
            >
              <Cell fill={metric.color} />
              <Cell fill="#f3f4f6" />
            </Pie>
          </PieChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
           <span className="text-[10px] font-bold text-gray-400">DQ</span>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { DataIssue, IssueSeverity } from '../types';
import { AlertTriangle, CheckCircle2, Zap, MoreHorizontal } from 'lucide-react';

interface IssueTableProps {
  issues: DataIssue[];
  onRepair: (issue: DataIssue) => void;
}

export const IssueTable: React.FC<IssueTableProps> = ({ issues, onRepair }) => {

  const getSeverityBadge = (severity: IssueSeverity) => {
    switch (severity) {
      case IssueSeverity.HIGH:
        return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800 border border-red-200">High</span>;
      case IssueSeverity.MEDIUM:
        return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800 border border-amber-200">Medium</span>;
      case IssueSeverity.LOW:
        return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800 border border-blue-200">Low</span>;
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
        <div>
            <h2 className="text-lg font-semibold text-gray-800">Key Problem Diagnosis</h2>
            <p className="text-sm text-gray-500">Prioritized anomalies requiring attention</p>
        </div>
        <button className="text-sm text-blue-600 font-medium hover:text-blue-800">
            View All Issues &rarr;
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-50 text-xs uppercase text-gray-500 font-semibold tracking-wider">
              <th className="px-6 py-3">Severity</th>
              <th className="px-6 py-3">Object / Table</th>
              <th className="px-6 py-3">Problem Description</th>
              <th className="px-6 py-3">Impact</th>
              <th className="px-6 py-3">AI Recommendation</th>
              <th className="px-6 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 text-sm">
            {issues.map((issue) => (
              <tr key={issue.id} className="hover:bg-blue-50/30 transition-colors group">
                <td className="px-6 py-4 whitespace-nowrap">
                  {getSeverityBadge(issue.severity)}
                </td>
                <td className="px-6 py-4">
                  <div className="font-medium text-gray-900">{issue.table}</div>
                  <div className="text-xs text-gray-500">{issue.field}</div>
                </td>
                <td className="px-6 py-4 text-gray-600 max-w-xs truncate" title={issue.description}>
                  {issue.description}
                </td>
                <td className="px-6 py-4 font-medium text-gray-700">
                  {issue.impact}
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2 text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-md border border-indigo-100 w-fit">
                    <Zap size={14} className="fill-indigo-600" />
                    <span className="text-xs font-medium">{issue.suggestion}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                    {issue.status === 'Fixed' ? (
                        <span className="flex items-center justify-end gap-1 text-green-600 font-medium text-xs">
                            <CheckCircle2 size={16} /> Fixed
                        </span>
                    ) : (
                        <button 
                            onClick={() => onRepair(issue)}
                            className="inline-flex items-center px-3 py-1.5 border border-transparent text-xs font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all opacity-0 group-hover:opacity-100"
                        >
                            Auto-Fix
                        </button>
                    )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { sendMessageToGemini } from '../services/geminiService';

interface ChatAgentProps {
  contextData: string;
}

export const ChatAgent: React.FC<ChatAgentProps> = ({ contextData }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      id: 'welcome', 
      role: 'model', 
      text: "Hello! I'm your Data Health Steward Agent. I've finished the nightly scan on the S/4HANA instance. I found some significant issues in the Material Master (MARA). How can I assist you?" 
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(input, contextData);

      const botMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText 
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
       const errorMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: "I'm having trouble connecting to my backend. Please check your API configuration." 
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      {/* Chat Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50 flex items-center gap-3">
        <div className="bg-gradient-to-br from-indigo-500 to-purple-600 p-2 rounded-lg shadow-md">
            <Bot size={20} className="text-white" />
        </div>
        <div>
            <h3 className="font-semibold text-gray-800">Agent Co-Pilot</h3>
            <p className="text-xs text-gray-500 flex items-center gap-1">
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                Active & Listening
            </p>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-gray-200' : 'bg-indigo-100'}`}>
                {msg.role === 'user' ? <User size={16} className="text-gray-600" /> : <Sparkles size={16} className="text-indigo-600" />}
              </div>
              <div className={`p-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-gray-100 text-gray-800 rounded-tl-none border border-gray-200'
              }`}>
                {msg.text.split('\n').map((line, i) => (
                    <React.Fragment key={i}>
                        {line}
                        {i < msg.text.split('\n').length - 1 && <br />}
                    </React.Fragment>
                ))}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
            <div className="flex justify-start">
                 <div className="flex gap-3 max-w-[85%]">
                     <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center flex-shrink-0">
                        <Sparkles size={16} className="text-indigo-600" />
                     </div>
                     <div className="bg-gray-50 border border-gray-100 p-4 rounded-2xl rounded-tl-none flex items-center gap-2 text-gray-500 text-sm">
                        <Loader2 size={16} className="animate-spin" />
                        Thinking...
                     </div>
                 </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 border-t border-gray-200 bg-white">
        <div className="flex items-center gap-2 bg-gray-50 rounded-xl px-4 py-2 border border-gray-200 focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-transparent transition-all">
          <input
            type="text"
            className="flex-1 bg-transparent border-none outline-none text-sm text-gray-800 placeholder-gray-400 py-2"
            placeholder="Ask to repair data or analyze trends..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`p-2 rounded-lg transition-colors ${
                !input.trim() || isLoading 
                ? 'text-gray-300' 
                : 'text-blue-600 hover:bg-blue-100'
            }`}
          >
            <Send size={18} />
          </button>
        </div>
        <div className="text-[10px] text-center text-gray-400 mt-2">
            AI can make mistakes. Please verify generated SQL fixes.
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Database, Search, FileCheck, CheckCircle2 } from 'lucide-react';

interface ScanningStepsProps {
  currentStep: number; // 0: Idle, 1: Extract, 2: Analyze, 3: Score, 4: Done
}

export const ScanningSteps: React.FC<ScanningStepsProps> = ({ currentStep }) => {
  const steps = [
    { id: 1, name: 'Sampling & Extract', icon: Database, desc: 'CDC Debezium' },
    { id: 2, name: 'AI Validation', icon: Search, desc: 'Semantic Check' },
    { id: 3, name: 'Scoring', icon: FileCheck, desc: 'Rule Engine' },
  ];

  if (currentStep === 0) return null;

  return (
    <div className="bg-white p-6 rounded-xl border border-blue-100 shadow-lg mb-6 animate-in slide-in-from-top-4 duration-500">
      <div className="flex justify-between relative">
        {/* Connecting Line */}
        <div className="absolute top-5 left-10 right-10 h-0.5 bg-gray-200 -z-0">
          <div 
            className="h-full bg-blue-500 transition-all duration-1000 ease-in-out" 
            style={{ width: `${((currentStep - 1) / 3) * 100}%` }}
          />
        </div>

        {steps.map((step) => {
          const isActive = currentStep === step.id;
          const isCompleted = currentStep > step.id;

          return (
            <div key={step.id} className="flex flex-col items-center relative z-10">
              <div 
                className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-500 ${
                  isActive ? 'bg-blue-600 text-white scale-110 shadow-blue-200 shadow-xl' : 
                  isCompleted ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-400'
                }`}
              >
                {isCompleted ? <CheckCircle2 size={20} /> : <step.icon size={18} />}
              </div>
              <h4 className={`mt-3 text-sm font-medium ${isActive ? 'text-blue-700' : 'text-gray-600'}`}>{step.name}</h4>
              <p className="text-xs text-gray-400 mt-1">{step.desc}</p>
            </div>
          );
        })}

         {/* Final Step Badge */}
         <div className="flex flex-col items-center relative z-10">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-500 ${currentStep === 4 ? 'bg-green-500 text-white scale-110' : 'bg-gray-200 text-gray-400'}`}>
                <CheckCircle2 size={20} />
            </div>
            <h4 className="mt-3 text-sm font-medium text-gray-600">Complete</h4>
        </div>
      </div>

      {currentStep < 4 && (
        <div className="mt-4 text-center">
            <span className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-medium animate-pulse">
               Processing batch #2910 from MARA...
            </span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { MetricCard } from './components/MetricCard';
import { IssueTable } from './components/IssueTable';
import { ChatAgent } from './components/ChatAgent';
import { ScanningSteps } from './components/ScanningSteps';
import { INITIAL_METRICS, INITIAL_ISSUES } from './constants';
import { DataIssue } from './types';
import { Play, RotateCcw, ShieldCheck } from 'lucide-react';

const App = () => {
  const [metrics, setMetrics] = useState(INITIAL_METRICS);
  const [issues, setIssues] = useState(INITIAL_ISSUES);
  const [scanStep, setScanStep] = useState(0); // 0: Idle

  // Context string for AI
  const [contextData, setContextData] = useState('');

  // Update context when data changes
  useEffect(() => {
    const context = `
      Overall Score: ${Math.round(metrics.reduce((acc, m) => acc + m.score, 0) / metrics.length)}/100.
      Metrics: ${metrics.map(m => `${m.name}: ${m.score}`).join(', ')}.
      Open Issues: ${issues.filter(i => i.status !== 'Fixed').length}.
      Top Issues: ${issues.map(i => `${i.type} in ${i.table} (${i.field})`).join('; ')}.
    `;
    setContextData(context);
  }, [metrics, issues]);

  const startActiveCheckup = () => {
    if (scanStep > 0 && scanStep < 4) return;

    setScanStep(1);

    // Simulate the process steps from the PPT
    setTimeout(() => setScanStep(2), 2000); // Validation
    setTimeout(() => setScanStep(3), 4500); // Scoring
    setTimeout(() => {
      setScanStep(4); // Done
      // Randomly tweak metrics to show "Live" update
      setMetrics(prev => prev.map(m => ({
        ...m,
        score: Math.min(100, Math.max(0, m.score + (Math.random() > 0.5 ? 1 : -1)))
      })));
    }, 6000);

    setTimeout(() => setScanStep(0), 8000); // Reset UI after delay
  };

  const handleRepair = (issueToFix: DataIssue) => {
    // Optimistic UI update
    setIssues(prev => prev.map(issue => 
      issue.id === issueToFix.id ? { ...issue, status: 'Fixed' } : issue
    ));

    // Boost score slightly
    setMetrics(prev => prev.map(m => {
      if (m.name === 'Completeness' && issueToFix.type === 'Missing Field') return { ...m, score: m.score + 1 };
      if (m.name === 'Uniqueness' && issueToFix.type === 'Duplicate') return { ...m, score: m.score + 1 };
      return m;
    }));
  };

  return (
    <Layout
      sidebar={<ChatAgent contextData={contextData} />}
    >
      {/* Top Controls */}
      <div className="flex justify-between items-end mb-6">
        <div>
           <h2 className="text-2xl font-bold text-gray-800">Health Overview</h2>
           <p className="text-gray-500 mt-1">Real-time governance dashboard</p>
        </div>
        <div className="flex gap-3">
            <button className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 text-sm font-medium hover:bg-gray-50 shadow-sm transition-colors">
                <RotateCcw size={16} />
                Load History
            </button>
            <button 
                onClick={startActiveCheckup}
                disabled={scanStep > 0}
                className={`flex items-center gap-2 px-5 py-2 rounded-lg text-white text-sm font-medium shadow-md transition-all ${
                    scanStep > 0 
                    ? 'bg-blue-400 cursor-wait' 
                    : 'bg-blue-600 hover:bg-blue-700 hover:shadow-lg hover:-translate-y-0.5'
                }`}
            >
                {scanStep > 0 ? (
                    <span className="flex items-center gap-2">Scanning...</span>
                ) : (
                    <>
                        <Play size={16} fill="currentColor" />
                        Run Active Checkup
                    </>
                )}
            </button>
        </div>
      </div>

      {/* Animation Area */}
      <ScanningSteps currentStep={scanStep} />

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {metrics.map((metric) => (
          <MetricCard key={metric.name} metric={metric} />
        ))}
      </div>

      {/* Main Content Split */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
         {/* Issues Table (Span 2) */}
         <div className="lg:col-span-2">
            <IssueTable issues={issues} onRepair={handleRepair} />
         </div>

         {/* Auto-Repair Strategy Panel (Span 1) - Based on PPT "Auto Repair & Loop" */}
         <div className="bg-gradient-to-br from-indigo-900 to-slate-900 rounded-xl p-6 text-white shadow-lg flex flex-col justify-between relative overflow-hidden">
            {/* Background pattern */}
            <div className="absolute top-0 right-0 -mr-8 -mt-8 w-32 h-32 bg-white opacity-5 rounded-full blur-2xl"></div>

            <div>
                <div className="flex items-center gap-2 mb-4 text-indigo-200">
                    <ShieldCheck size={20} />
                    <span className="uppercase tracking-wider text-xs font-bold">Auto-Repair Strategy</span>
                </div>
                <h3 className="text-xl font-bold mb-4">Active Correction Policies</h3>

                <div className="space-y-4">
                    <div className="flex items-center justify-between p-3 bg-white/10 rounded-lg backdrop-blur-sm border border-white/5">
                        <div className="text-sm">
                            <div className="text-gray-300 text-xs">Formatted Fixes</div>
                            <div className="font-semibold">2,316</div>
                        </div>
                        <div className="text-green-400 text-xs font-bold bg-green-400/20 px-2 py-1 rounded">Auto Executed</div>
                    </div>

                    <div className="flex items-center justify-between p-3 bg-white/10 rounded-lg backdrop-blur-sm border border-white/5">
                        <div className="text-sm">
                            <div className="text-gray-300 text-xs">AI Value Inference</div>
                            <div className="font-semibold">8,612</div>
                        </div>
                         <div className="text-amber-400 text-xs font-bold bg-amber-400/20 px-2 py-1 rounded">Pending Audit</div>
                    </div>

                    <div className="flex items-center justify-between p-3 bg-white/10 rounded-lg backdrop-blur-sm border border-white/5">
                        <div className="text-sm">
                            <div className="text-gray-300 text-xs">Domain Validations</div>
