import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { sendMessageToGemini } from '../services/geminiService';

interface ChatAgentProps {
  contextData: string;
}

export const ChatAgent: React.FC<ChatAgentProps> = ({ contextData }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      id: 'welcome', 
      role: 'model', 
      text: "你好！我是你的 SAP 数据健康管家。我已经完成了对 S/4HANA 实例的夜间扫描。\n\n我在物料主数据 (MARA) 中发现了一些显著的质量问题。请问需要我先从哪里开始分析？" 
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(input, contextData);

      const botMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText 
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
       const errorMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: "抱歉，连接 AI 大脑时出现问题。请检查您的 API 配置。" 
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      {/* Chat Header */}
      <div className="p-5 border-b border-slate-100 bg-white flex items-center gap-4 shadow-sm z-10">
        <div className="relative">
            <div className="bg-gradient-to-tr from-indigo-600 to-violet-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
                <Bot size={22} className="text-white" />
            </div>
            <span className="absolute -bottom-1 -right-1 flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500 border-2 border-white"></span>
            </span>
        </div>
        <div>
            <h3 className="font-bold text-slate-800 text-sm">智能数据助手</h3>
            <p className="text-xs text-slate-500 font-medium mt-0.5">
                Gemini 2.5 Flash Driven
            </p>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-5 space-y-6 scrollbar-hide bg-slate-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm border border-slate-100 ${msg.role === 'user' ? 'bg-white' : 'bg-indigo-600'}`}>
                {msg.role === 'user' ? <User size={16} className="text-slate-600" /> : <Sparkles size={16} className="text-white fill-indigo-200" />}
              </div>
              <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
              }`}>
                {msg.text.split('\n').map((line, i) => (
                    <React.Fragment key={i}>
                        {line}
                        {i < msg.text.split('\n').length - 1 && <br />}
                    </React.Fragment>
                ))}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
            <div className="flex justify-start">
                 <div className="flex gap-3 max-w-[85%]">
                     <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center flex-shrink-0 shadow-sm">
                        <Sparkles size={16} className="text-white" />
                     </div>
                     <div className="bg-white border border-slate-100 px-4 py-3 rounded-2xl rounded-tl-none flex items-center gap-2 text-slate-500 text-sm shadow-sm">
                        <Loader2 size={16} className="animate-spin text-indigo-500" />
                        思考中...
                     </div>
                 </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 border-t border-slate-100 bg-white">
        <div className="flex items-center gap-2 bg-slate-50 rounded-xl px-4 py-2 border border-slate-200 focus-within:ring-2 focus-within:ring-indigo-500/20 focus-within:border-indigo-500 transition-all shadow-inner">
          <input
            type="text"
            className="flex-1 bg-transparent border-none outline-none text-sm text-slate-800 placeholder-slate-400 py-2.5"
            placeholder="输入指令修复数据或分析趋势..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`p-2 rounded-lg transition-all duration-200 ${
                !input.trim() || isLoading 
                ? 'text-slate-300' 
                : 'text-white bg-indigo-600 hover:bg-indigo-700 shadow-md hover:shadow-lg transform hover:-translate-y-0.5'
            }`}
          >
            <Send size={16} />
          </button>
        </div>
        <div className="text-[10px] text-center text-slate-400 mt-3 font-medium">
            AI 可能会犯错。请务必在执行前验证 SQL 修复脚本。
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Database, Search, FileCheck, CheckCircle2 } from 'lucide-react';

interface ScanningStepsProps {
  currentStep: number; // 0: Idle, 1: Extract, 2: Analyze, 3: Score, 4: Done
}

export const ScanningSteps: React.FC<ScanningStepsProps> = ({ currentStep }) => {
  const steps = [
    { id: 1, name: '采样与提取', icon: Database, desc: 'CDC Debezium' },
    { id: 2, name: 'AI 语义校验', icon: Search, desc: 'Semantic Check' },
    { id: 3, name: '评分与归档', icon: FileCheck, desc: 'Rule Engine' },
  ];

  if (currentStep === 0) return null;

  return (
    <div className="bg-white p-8 rounded-2xl border border-blue-100 shadow-xl shadow-blue-500/5 mb-8 animate-in slide-in-from-top-4 duration-500 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-blue-50 rounded-full blur-3xl -mr-16 -mt-16 opacity-50 pointer-events-none"></div>

      <div className="flex justify-between relative max-w-4xl mx-auto">
        {/* Connecting Line */}
        <div className="absolute top-6 left-12 right-12 h-1 bg-slate-100 rounded-full -z-0">
          <div 
            className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full transition-all duration-1000 ease-in-out shadow-[0_0_10px_rgba(59,130,246,0.5)]" 
            style={{ width: `${((currentStep - 1) / 3) * 100}%` }}
          />
        </div>

        {steps.map((step) => {
          const isActive = currentStep === step.id;
          const isCompleted = currentStep > step.id;

          return (
            <div key={step.id} className="flex flex-col items-center relative z-10 group">
              <div 
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-500 border-4 ${
                  isActive ? 'bg-white border-blue-500 text-blue-600 scale-110 shadow-lg shadow-blue-200' : 
                  isCompleted ? 'bg-blue-500 border-blue-500 text-white' : 'bg-white border-slate-200 text-slate-300'
                }`}
              >
                {isCompleted ? <CheckCircle2 size={24} /> : <step.icon size={20} />}
              </div>
              <h4 className={`mt-4 text-sm font-bold transition-colors ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>{step.name}</h4>
              <p className="text-xs text-slate-400 mt-1 font-medium">{step.desc}</p>
            </div>
          );
        })}

         {/* Final Step Badge */}
         <div className="flex flex-col items-center relative z-10">
            <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-500 border-4 ${currentStep === 4 ? 'bg-green-500 border-green-500 text-white scale-110 shadow-lg shadow-green-200' : 'bg-white border-slate-200 text-slate-300'}`}>
                <CheckCircle2 size={24} />
            </div>
            <h4 className={`mt-4 text-sm font-bold transition-colors ${currentStep === 4 ? 'text-green-600' : 'text-slate-600'}`}>完成</h4>
        </div>
      </div>

      {currentStep < 4 && (
        <div className="mt-8 text-center">
            <span className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-blue-50 text-blue-700 text-xs font-bold animate-pulse border border-blue-100">
               <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span>
               正在处理 MARA 批次 #2910...
            </span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { MetricCard } from './components/MetricCard';
import { IssueTable } from './components/IssueTable';
import { ChatAgent } from './components/ChatAgent';
import { ScanningSteps } from './components/ScanningSteps';
import { INITIAL_METRICS, INITIAL_ISSUES } from './constants';
import { DataIssue } from './types';
import { Play, RotateCcw, ShieldCheck, Zap, Activity } from 'lucide-react';

const App = () => {
  const [metrics, setMetrics] = useState(INITIAL_METRICS);
  const [issues, setIssues] = useState(INITIAL_ISSUES);
  const [scanStep, setScanStep] = useState(0); // 0: Idle

  // Context string for AI
  const [contextData, setContextData] = useState('');

  // Update context when data changes
  useEffect(() => {
    const context = `
      Overall Score: ${Math.round(metrics.reduce((acc, m) => acc + m.score, 0) / metrics.length)}/100.
      Metrics: ${metrics.map(m => `${m.name}: ${m.score}`).join(', ')}.
      Open Issues: ${issues.filter(i => i.status !== 'Fixed').length}.
      Top Issues: ${issues.map(i => `${i.type} in ${i.table} (${i.field})`).join('; ')}.
    `;
    setContextData(context);
  }, [metrics, issues]);

  const startActiveCheckup = () => {
    if (scanStep > 0 && scanStep < 4) return;

    setScanStep(1);

    // Simulate the process steps from the PPT
    setTimeout(() => setScanStep(2), 2000); // Validation
    setTimeout(() => setScanStep(3), 4500); // Scoring
    setTimeout(() => {
      setScanStep(4); // Done
      // Randomly tweak metrics to show "Live" update
      setMetrics(prev => prev.map(m => ({
        ...m,
        score: Math.min(100, Math.max(0, m.score + (Math.random() > 0.5 ? 1 : -1)))
      })));
    }, 6000);

    setTimeout(() => setScanStep(0), 8000); // Reset UI after delay
  };

  const handleRepair = (issueToFix: DataIssue) => {
    // Optimistic UI update
    setIssues(prev => prev.map(issue => 
      issue.id === issueToFix.id ? { ...issue, status: 'Fixed' } : issue
    ));

    // Boost score slightly
    setMetrics(prev => prev.map(m => {
      if (m.name.includes('Completeness') && issueToFix.type === 'Missing Field') return { ...m, score: m.score + 1 };
      if (m.name.includes('Uniqueness') && issueToFix.type === 'Duplicate') return { ...m, score: m.score + 1 };
      return m;
    }));
  };

  return (
    <Layout
      sidebar={<ChatAgent contextData={contextData} />}
    >
      {/* Top Controls */}
      <div className="flex justify-between items-end mb-8">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 tracking-tight">健康概览 (Health Overview)</h2>
           <p className="text-slate-500 mt-1 flex items-center gap-2">
              <Activity size={16} className="text-blue-500" />
              实时数据治理仪表盘
           </p>
        </div>
        <div className="flex gap-3">
            <button className="flex items-center gap-2 px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-slate-700 text-sm font-semibold hover:bg-slate-50 hover:border-slate-300 shadow-sm transition-all">
                <RotateCcw size={16} />
                加载历史记录
            </button>
            <button 
                onClick={startActiveCheckup}
                disabled={scanStep > 0}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-white text-sm font-semibold shadow-md transition-all ${
                    scanStep > 0 
                    ? 'bg-blue-400 cursor-wait' 
                    : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 hover:shadow-lg hover:shadow-blue-500/25 hover:-translate-y-0.5'
                }`}
            >
                {scanStep > 0 ? (
                    <span className="flex items-center gap-2">扫描中...</span>
                ) : (
                    <>
                        <Play size={16} fill="currentColor" />
                        执行主动体检
                    </>
                )}
            </button>
        </div>
      </div>

      {/* Animation Area */}
      <ScanningSteps currentStep={scanStep} />

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {metrics.map((metric) => (
          <MetricCard key={metric.name} metric={metric} />
        ))}
      </div>

