                    <Zap size={14} className="fill-indigo-500 text-indigo-500 shrink-0" />
                    <span className="text-xs font-medium truncate" title={issue.suggestion}>{issue.suggestion}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                    {issue.status === 'Fixed' ? (
                        <span className="flex items-center justify-end gap-1.5 text-green-600 font-bold text-xs bg-green-50 py-1.5 px-3 rounded-lg border border-green-100 w-fit ml-auto">
                            <CheckCircle2 size={14} /> 已修复
                        </span>
                    ) : (
                        <button 
                            onClick={() => onRepair(issue)}
                            className="inline-flex items-center px-4 py-1.5 border border-blue-200 text-xs font-semibold rounded-lg shadow-sm text-blue-600 bg-white hover:bg-blue-600 hover:text-white hover:border-blue-600 focus:outline-none transition-all duration-200 opacity-0 group-hover:opacity-100 translate-x-2 group-hover:translate-x-0"
                        >
                            自动修复
                        </button>
                    )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

