                <th className="px-6 py-4 border-b border-slate-200">严重程度</th>
                <th className="px-6 py-4 border-b border-slate-200">表 / 字段</th>
                <th className="px-6 py-4 border-b border-slate-200 w-1/4">详细描述</th>
